command:
// MAPEO de habilidades organizadas por categoría
const categorias = {
  physical: {
    nombre: "Physical",
    habilidades: {
      "agi": { nombre: "Agility / Agilidad", attr: "spd" },
      "ath": { nombre: "Athletics / Atletismo", attr: "str" },
      "hwp": { nombre: "Heavy Weapons / Armas Pesadas", attr: "str" },
      "lwp": { nombre: "Light Weapons / Armas Ligeras", attr: "spd" },
      "stl": { nombre: "Stealth / Sigilo", attr: "spd" },
      "thv": { nombre: "Thievery / Hurto", attr: "spd" }
    }
  },
  cognitive: {
    nombre: "Cognitive",
    habilidades: {
      "cra": { nombre: "Crafting / Artesanía", attr: "int" },
      "ded": { nombre: "Deduction / Deducción", attr: "int" },
      "dis": { nombre: "Discipline / Disciplina", attr: "wil" },
      "inm": { nombre: "Intimidation / Intimidación", attr: "wil" },
      "lor": { nombre: "Lore / Saber", attr: "int" },
      "med": { nombre: "Medicine / Medicina", attr: "int" }
    }
  },
  spiritual: {
    nombre: "Spiritual",
    habilidades: {
      "dec": { nombre: "Deception / Engaño", attr: "pre" },
      "ins": { nombre: "Insight / Perspicacia", attr: "awa" },
      "lea": { nombre: "Leadership / Liderazgo", attr: "pre" },
      "prc": { nombre: "Perception / Percepción", attr: "awa" },
      "prs": { nombre: "Persuasion / Persuasión", attr: "pre" },
      "sur": { nombre: "Survival / Supervivencia", attr: "awa" }
    }
  }
};

const attrNames = {
  "str": "STR", "spd": "SPD", "int": "INT",
  "wil": "WIL", "awa": "AWA", "pre": "PRE"
};

// Buscar actor
let actor = canvas.tokens.controlled[0]?.actor ?? game.user.character;
if (!actor) {
  ui.notifications.error("No tienes un personaje activo ni ningún token seleccionado.");
  return;
}

const actorSkills = actor.system.skills ?? {};
const actorAttrs = actor.system.attributes ?? {};

// Convertir habilidades a arrays para poder iterar por filas
const cols = Object.values(categorias).map(cat => {
  return {
    nombre: cat.nombre,
    skills: Object.entries(cat.habilidades).map(([key, data]) => {
      const skillVal = actorSkills[key]?.rank ?? 0;
      const attrVal = actorAttrs[data.attr]?.value ?? 0;
      return {
        key,
        nombre: data.nombre,
        attr: attrNames[data.attr],
        total: skillVal + attrVal
      };
    })
  };
});

const numRows = Math.max(...cols.map(c => c.skills.length));

// Generar HTML
let htmlContent = `
<style>
  .skills-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 6px;
  }
  .skills-table th {
    font-family: 'Modesto Condensed', serif;
    font-size: 22px;
    color: #f4e8c1;
    padding: 8px;
    text-align: center;
  }
  .skill-cell {
    background: #1e3a5f;
    border: 1px solid #3a6186;
    border-radius: 4px;
    padding: 10px 14px;
    text-align: center;
    cursor: pointer;
    transition: all 0.2s;
  }
  .skill-cell:hover {
    background: #2a4a6f;
    border-color: #5a8ab6;
    transform: scale(1.03);
  }
  .skill-name { color: #f4e8c1; font-size: 13px; }
  .skill-attr { color: #8ab4d4; font-size: 11px; margin-left: 4px; }
  .skill-total { color: #f4e8c1; font-size: 13px; }
</style>

<table class="skills-table">
  <thead>
    <tr>
      ${cols.map(c => `<th>${c.nombre}</th>`).join('')}
    </tr>
  </thead>
  <tbody>
`;

for (let i = 0; i < numRows; i++) {
  htmlContent += '<tr>';
  for (const col of cols) {
    const skill = col.skills[i];
    if (skill) {
      htmlContent += `
        <td class="skill-cell" data-skill="${skill.key}">
          <span class="skill-name">${skill.nombre}</span>
          <span class="skill-attr">${skill.attr}</span>
          <span class="skill-total">(+${skill.total})</span>
        </td>
      `;
    } else {
      htmlContent += '<td></td>';
    }
  }
  htmlContent += '</tr>';
}

htmlContent += `
  </tbody>
</table>
`;

// Crear diálogo
const dialog = new Dialog({
  title: `${actor.name}'s Skills`,
  content: htmlContent,
  buttons: {},
  render: html => {
    html.find(".skill-cell").on("click", function() {
      const skillKey = $(this).data("skill");
      dialog.close();
      actor.rollSkill(skillKey, { chatMessage: true });
    });
  }
}, { width: 650 }).render(true);
